import{_ as s,o as e,c as t,a2 as n}from"./chunks/framework.B72_uj9U.js";const u=JSON.parse('{"title":"Getting Started","description":"","frontmatter":{},"headers":[],"relativePath":"guide/getting-started.md","filePath":"guide/getting-started.md","lastUpdated":null}'),i={name:"guide/getting-started.md"};function l(p,a,o,r,d,c){return e(),t("div",null,[...a[0]||(a[0]=[n(`<h1 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h1><p>This guide walks you through setting up DINOForge for development or mod authoring.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li><a href="https://dotnet.microsoft.com/download" target="_blank" rel="noreferrer">.NET 8 SDK</a> or later</li><li><a href="https://nodejs.org/" target="_blank" rel="noreferrer">Node.js 20+</a> (for docs only)</li><li>Diplomacy is Not an Option (Steam)</li><li>Git</li></ul><h2 id="install-bepinex" tabindex="-1">Install BepInEx <a class="header-anchor" href="#install-bepinex" aria-label="Permalink to &quot;Install BepInEx&quot;">​</a></h2><p>DINOForge runs on a <strong>modified BepInEx 5</strong> build with Unity ECS support. Standard BepInEx from GitHub will not work.</p><ol><li>Download <strong>BepInEx 5 with Unity ECS Support</strong> from <a href="https://www.nexusmods.com/diplomacyisnotanoption/mods/1" target="_blank" rel="noreferrer">Nexus Mods</a></li><li>Extract into your DINO game directory (where the <code>.exe</code> lives)</li><li>Verify the folder structure:</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GameRoot/</span></span>
<span class="line"><span>  winhttp.dll              # Modified Doorstop pre-loader</span></span>
<span class="line"><span>  doorstop_config.ini</span></span>
<span class="line"><span>  BepInEx/</span></span>
<span class="line"><span>    plugins/               # Standard plugins (empty for DINO)</span></span>
<span class="line"><span>    ecs_plugins/           # WHERE DINO MODS GO</span></span>
<span class="line"><span>    config/                # Configuration files</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Standard BepInEx does <strong>not</strong> work with DINO. The game uses full Unity ECS (DOTS) with Burst compilation, which requires a modified Doorstop pre-loader fork.</p></div><ol start="4"><li>Launch the game once to let BepInEx initialize, then close it.</li></ol><h2 id="clone-and-build" tabindex="-1">Clone and Build <a class="header-anchor" href="#clone-and-build" aria-label="Permalink to &quot;Clone and Build&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/KooshaPari/Dino.git</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Dino</span></span></code></pre></div><p>Build the solution:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dotnet</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> src/DINOForge.sln</span></span></code></pre></div><p>Run tests to verify everything works:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dotnet</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> src/DINOForge.sln</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --verbosity</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> normal</span></span></code></pre></div><h2 id="project-structure" tabindex="-1">Project Structure <a class="header-anchor" href="#project-structure" aria-label="Permalink to &quot;Project Structure&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>DINOForge/</span></span>
<span class="line"><span>  src/</span></span>
<span class="line"><span>    Runtime/       # BepInEx plugin — bootstrap, ECS detection, hooks</span></span>
<span class="line"><span>    SDK/           # Public mod API — registries, schemas, pack loaders</span></span>
<span class="line"><span>    Tools/</span></span>
<span class="line"><span>      PackCompiler/  # CLI: validate, build, package packs</span></span>
<span class="line"><span>      DumpTools/     # Entity/component dump utilities</span></span>
<span class="line"><span>    Tests/         # xUnit test suite</span></span>
<span class="line"><span>  packs/           # Content packs and example mods</span></span>
<span class="line"><span>  schemas/         # Canonical JSON/YAML schema definitions</span></span>
<span class="line"><span>  docs/            # This documentation site</span></span></code></pre></div><h2 id="load-a-pack" tabindex="-1">Load a Pack <a class="header-anchor" href="#load-a-pack" aria-label="Permalink to &quot;Load a Pack&quot;">​</a></h2><p>Once built, the Runtime DLL goes into <code>BepInEx/ecs_plugins/</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>BepInEx/ecs_plugins/DINOForge.Runtime.dll</span></span></code></pre></div><p>Content packs live in a <code>packs/</code> directory relative to the game root. The runtime discovers and loads them at boot.</p><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="/guide/quick-start">Quick Start</a> — Create your first pack in 5 minutes</li><li><a href="/guide/creating-packs">Creating Packs</a> — Full pack authoring guide</li><li><a href="/concepts/architecture">Architecture</a> — Understand the layered design</li></ul>`,24)])])}const g=s(i,[["render",l]]);export{u as __pageData,g as default};
